typedef struct tagSOCK_ADDR {   USHORT family;
CHAR   data[126];
} DIAG_SOCKADDR, *PDIAG_SOCK_ADDR;
成员 family
类型： USHORT 套接字地址组。 data[126]
类型： CHAR[126]
所有不同套接字地址结构的最大大小。

typedef struct tagDiagnosticsInfo {
long  cost;   ULONG flags;
} DiagnosticsInfo, *PDiagnosticsInfo;
成员 cost
类型： long
诊断完成所需的时间（以秒为单位）。 值为零或负值表示成本可忽略不计。 任何正值都
会导致引擎调整整体诊断过程。 flags
类型： ULONG
保留。

typedef struct tagHelperAttributeInfo {
LPWSTR         pwszName;   ATTRIBUTE_TYPE type;
} HelperAttributeInfo, *PHelperAttributeInfo;
成员 pwszName
类型： [字符串] LPWSTR
指向包含帮助程序属性名称的以 null 结尾的字符串的指针。 type
类型： ATTRIBUTE_TYPE 帮助程序属性的类型。

typedef struct tagLIFE_TIME {
FILETIME startTime;   FILETIME endTime;
} LIFE_TIME, *PLIFE_TIME;
成员 startTime
类型： FILETIME
问题实例开始的时间。 endTime
类型： FILETIME
问题实例结束的时间。

typedef struct tagOCTET_STRING {
DWORD dwLength;   BYTE  *lpValue;
} OCTET_STRING, *POCTET_STRING;
成员 dwLength
类型：DWORD 数据的长度。 lpValue
类型： [size_is (dwLength) ]BYTE* 指向包含数据的字节数组的指针。

typedef struct tagRepairInfo {   GUID         guid;
LPWSTR       pwszClassName;   LPWSTR       pwszDescription;   DWORD        sidType;
long         cost;   ULONG        flags;   REPAIR_SCOPE scope;   REPAIR_RISK  risk;   UiInfo       UiInfo;
int          rootCauseIndex;} RepairInfo, *PRepairInfo;
成员 guid
此修复的唯一 GUID。 pwszClassName
指向以用户友好方式包含帮助程序类名称的以 null 结尾的字符串的指针。 pwszDescription
指向以用户友好方式描述修复的以 null 结尾的字符串的指针。 sidType
如果修复需要某些用户上下文或权限，则WELL_KNOWN_SID_TYPE之一。 cost
执行修复所需的秒数。 flags
有关修复的其他信息。值

typedef struct tagRepairInfoEx {   RepairInfo repair;
USHORT     repairRank;
} RepairInfoEx, *PRepairInfoEx;
成员 repair
类型： RepairInfo 详细的修复信息。 repairRank
类型： USHORT
相对于与事件关联的 RootCauseInfo 结构中的其他修复的修复的排名。 排名为 1 的修复预期与问题更相关，因此将是尝试的第一次修复。 无论其等级如何，都不能保证任何单
个修复的成功。

